<script setup lang="ts">import { expansionFeature, focusFeature, keyboardFeature, selectionFeature } from '@fex/components-core'; import Button from '@fex/components-vue/ui/button'; import Card from '@fex/components-vue/ui/card'; import { ref } from 'vue'; import DemoTree from './demo-tree.vue'; import { departmentFieldNames, departmentTreeData } from './data'; const expandedKeys=ref<readonly (string|number)[]>(['company','engineering']); const selectedKeys=ref<readonly (string|number)[]>([]); const features=[expansionFeature(),selectionFeature(),focusFeature(),keyboardFeature()]; function selectFrontend(){expandedKeys.value=['company','engineering'];selectedKeys.value=['frontend']}</script>
<template><Card title="Controlled state" description="Expansion and selection can be owned outside Tree."><div class="mb-space-md flex flex-wrap gap-space-sm"><Button size="sm" variant="outline" @click="expandedKeys=['company','engineering','product']">Expand departments</Button><Button size="sm" variant="outline" @click="selectFrontend">Select Frontend</Button></div><DemoTree :tree-data="departmentTreeData" :field-names="departmentFieldNames" :is-leaf="node => node.childCount === 0" :expanded-keys="expandedKeys" :on-expanded-keys-change="keys => expandedKeys=keys" :selected-keys="selectedKeys" :on-selected-keys-change="keys => selectedKeys=keys" :features="features" class="max-w-xl rounded-md border border-border bg-background p-space-sm" /></Card></template>
